try(Sys.setlocale("LC_CTYPE", "nb_NO.UTF-8"), silent = TRUE)

#### USER METRICS / WEBR LOGGING ####
SUPABASE_BASE_URL <- Sys.getenv(
  "SUPABASE_BASE_URL",
  unset = "https://qnixtvksfourazmwmvul.supabase.co"
)

SUPABASE_KEY <- Sys.getenv(
  "SUPABASE_KEY",
  unset = "sb_publishable_ehXOEZiamKtLYRt9fU0w1Q_boRexRK2"
)

APP_NAME_METRICS <- "boligstatistikk_dashboard"

#### LAST INN FERDIG PROSESSERT DATA ####
