#### SERVER ####
server <- function(input, output, session) {
  
  send_metric <- function(event_name, event_value = NULL, app_name = APP_NAME_METRICS) {
    session$sendCustomMessage(
      "log_event",
      list(
        event_name = event_name,
        event_value = event_value,
        app_name = app_name
      )
    )
  }
  
  observe({
    send_metric(
      event_name = "app_start",
      event_value = paste0("started_at=", format(Sys.time(), "%Y-%m-%d %H:%M:%S"))
    )
  })
  
  make_key <- function(...) {
    parts <- list(...)
    paste(
      vapply(parts, function(x) {
        if (is.null(x)) return("NULL")
        paste(as.character(x), collapse = "||")
      }, character(1)),
      collapse = "___"
    )
  }
  
  apply_plotly_cursor_fix <- function(p) {
    p |>
      onRender("
        function(el, x) {
          var nodes = el.getElementsByClassName('cursor-crosshair');
          for (var i = 0; i < nodes.length; i++) {
            nodes[i].style.cursor = 'default';
          }
          var drags = el.getElementsByClassName('draglayer');
          for (var j = 0; j < drags.length; j++) {
            drags[j].style.cursor = 'default';
          }
        }
      ")
  }
  
  plot_cache <- reactiveValues(
    cmp = list(),
    trend = list(),
    bygtype = list(),
    ferdig = list()
  )
  
  table_cache <- reactiveValues(
    endring_komm = list(),
    endring_fylke = list()
  )
  
  observe({
    if (isTRUE(input$hc_mode)) {
      shinyjs::runjs("document.body.classList.add('hc-mode');")
    } else {
      shinyjs::runjs("document.body.classList.remove('hc-mode');")
    }
  })
  
  observeEvent(input$main_tab, {
    send_metric(
      event_name = "tab_open",
      event_value = input$main_tab
    )
  }, ignoreInit = TRUE)
  
  observeEvent(input$hc_mode, {
    send_metric(
      event_name = "toggle_change",
      event_value = paste0("hc_mode=", input$hc_mode)
    )
  }, ignoreInit = TRUE)
  
  observeEvent(list(input$nivaa, input$geografi, input$aar, input$visning), {
    send_metric(
      event_name = "filter_change",
      event_value = paste0(
        "tab=Boligmassen; ",
        "nivaa=", input$nivaa, "; ",
        "geografi=", paste(input$geografi, collapse = "|"), "; ",
        "aar=", input$aar, "; ",
        "visning=", input$visning
      )
    )
  }, ignoreInit = TRUE)
  
  observeEvent(list(input$nivaa_cmp, input$bygn_cmp, input$aar_cmp), {
    send_metric(
      event_name = "filter_change",
      event_value = paste0(
        "tab=Sammenligne boligmassen; ",
        "nivaa=", input$nivaa_cmp, "; ",
        "bygn_cmp=", input$bygn_cmp, "; ",
        "aar=", input$aar_cmp
      )
    )
  }, ignoreInit = TRUE)
  
  observeEvent(list(input$nivaa_trend, input$geografi_trend, input$bygn_trend), {
    send_metric(
      event_name = "filter_change",
      event_value = paste0(
        "tab=Tidstrend boligmassen; ",
        "nivaa=", input$nivaa_trend, "; ",
        "geografi=", paste(input$geografi_trend, collapse = "|"), "; ",
        "bygn_trend=", input$bygn_trend
      )
    )
  }, ignoreInit = TRUE)
  
  observeEvent(list(input$bygn_endring, input$periode_endring), {
    send_metric(
      event_name = "filter_change",
      event_value = paste0(
        "tab=Endringer boligmassen; ",
        "bygn_endring=", input$bygn_endring, "; ",
        "periode=", paste(input$periode_endring, collapse = "-")
      )
    )
  }, ignoreInit = TRUE)
  
  observeEvent(list(input$nivaa_bygtype, input$geografi_bygtype, input$periode_bygtype), {
    send_metric(
      event_name = "filter_change",
      event_value = paste0(
        "tab=Endringer bygningstyper; ",
        "nivaa=", input$nivaa_bygtype, "; ",
        "geografi=", paste(input$geografi_bygtype, collapse = "|"), "; ",
        "periode=", paste(input$periode_bygtype, collapse = "-")
      )
    )
  }, ignoreInit = TRUE)
  
  observeEvent(list(input$nivaa_ferdig, input$geografi_ferdig, input$bygn_ferdig), {
    send_metric(
      event_name = "filter_change",
      event_value = paste0(
        "tab=Ferdigstilte boliger; ",
        "nivaa=", input$nivaa_ferdig, "; ",
        "geografi=", paste(input$geografi_ferdig, collapse = "|"), "; ",
        "bygn_ferdig=", input$bygn_ferdig
      )
    )
  }, ignoreInit = TRUE)
  
  ## FANE 1: BOLIGMASSEN ------------------------------------------
  
  observeEvent(input$nivaa, {
    if (input$nivaa == "Fylke") {
      updatePickerInput(
        session, "geografi",
        choices = available_fylker,
        selected = "Rogaland"
      )
    } else if (input$nivaa == "Kommuner") {
      updatePickerInput(
        session, "geografi",
        choices = kommuner_rogaland,
        selected = NULL
      )
    } else {
      updatePickerInput(
        session, "geografi",
        choices = "Norge",
        selected = "Norge"
      )
    }
  })
  
  output$region_title <- renderUI({
    label <- if (input$nivaa == "Norge") {
      "Norge"
    } else if (is.null(input$geografi) || length(input$geografi) == 0) {
      paste(input$nivaa, "(ingen valg)")
    } else if (length(input$geografi) == 1) {
      input$geografi
    } else {
      paste0(input$nivaa, " (", length(input$geografi), " valgte enheter)")
    }
    
    tags$p(
      paste("Region  •", label),
      style = "text-align:center; margin-top:-6px; margin-bottom:6px;"
    )
  })
  
  boligdata <- reactive({
    d <- df_bolig |> dplyr::filter(aar == input$aar)
    
    if (input$nivaa != "Norge" &&
        (is.null(input$geografi) || length(input$geografi) == 0)) {
      return(d[0, ])
    }
    
    if (input$nivaa == "Fylke") {
      d <- d |>
        dplyr::filter(fylke %in% input$geografi) |>
        dplyr::mutate(gruppe = fylke)
      
