  lag_endringstabell <- function(data, geo_var, start_year, end_year,
                                 geo_label = "Geografisk enhet") {
    geo_var <- rlang::enquo(geo_var)
    
    d <- data |>
      dplyr::filter(aar %in% c(as.character(start_year), as.character(end_year))) |>
      dplyr::group_by(!!geo_var, aar) |>
      dplyr::summarise(antall = sum(value, na.rm = TRUE), .groups = "drop")
    
    wide <- d |>
      tidyr::pivot_wider(
        names_from = aar,
        values_from = antall,
        values_fill = 0
      )
    
    names(wide)[names(wide) == as.character(start_year)] <- "antall_start"
    names(wide)[names(wide) == as.character(end_year)]   <- "antall_siste"
    
    wide <- wide |>
      dplyr::mutate(
        endring_antall = antall_siste - antall_start,
        endring_pct = dplyr::if_else(
          antall_start > 0,
          (endring_antall / antall_start) * 100,
          NA_real_
        )
      )
    
    total_row <- wide |>
      dplyr::summarise(
        !!geo_var := "Totalt",
        antall_start = sum(antall_start, na.rm = TRUE),
        antall_siste = sum(antall_siste, na.rm = TRUE),
        endring_antall = sum(endring_antall, na.rm = TRUE),
        endring_pct = dplyr::if_else(
          antall_start > 0,
          (antall_siste - antall_start) / antall_start * 100,
          NA_real_
        )
      )
    
    wide_tot <- dplyr::bind_rows(wide, total_row)
    
    wide_tot <- wide_tot |>
      dplyr::mutate(
        er_totalt = (!!geo_var == "Totalt")
      ) |>
      dplyr::arrange(er_totalt, dplyr::desc(endring_pct)) |>
      dplyr::select(-er_totalt)
    
    wide_fmt <- wide_tot |>
      dplyr::mutate(
        `Antall siste år` = format(
          antall_siste,
          big.mark = " ",
          decimal.mark = ",",
          scientific = FALSE
        ),
        `Endring antall` = format(
          endring_antall,
          big.mark = " ",
          decimal.mark = ",",
          scientific = FALSE
        ),
        `Endring i %` = dplyr::if_else(
          is.na(endring_pct),
          "",
          paste0(
            format(round(endring_pct, 1),
                   decimal.mark = ",",
                   nsmall = 1),
            " %"
          )
        )
      ) |>
      dplyr::transmute(
        !!geo_label := !!geo_var,
        `Antall siste år`,
        `Endring antall`,
        `Endring i %`
      )
    
    wide_fmt
  }
  
