    req(input$nivaa_bygtype, input$periode_bygtype)
    
    yrs <- sort(as.integer(input$periode_bygtype))
    start_year <- as.character(yrs[1])
    end_year   <- as.character(yrs[2])
    
    d <- df_bolig |>
      dplyr::filter(aar %in% c(start_year, end_year))
    
    if (input$nivaa_bygtype == "Fylke") {
      if (is.null(input$geografi_bygtype) || length(input$geografi_bygtype) == 0)
        return(d[0, ])
      d <- d |> dplyr::filter(fylke %in% input$geografi_bygtype)
      
    } else if (input$nivaa_bygtype == "Kommuner") {
      if (is.null(input$geografi_bygtype) || length(input$geografi_bygtype) == 0)
        return(d[0, ])
      d <- d |> dplyr::filter(
        fylke == "Rogaland",
        region %in% input$geografi_bygtype
      )
    }
    
    agg <- d |>
      dplyr::group_by(aar, bygnType) |>
      dplyr::summarise(antall = sum(value, na.rm = TRUE), .groups = "drop")
    
    wide <- agg |>
      tidyr::pivot_wider(
        names_from = aar,
        values_from = antall,
        values_fill = 0
      )
    
    if (!start_year %in% names(wide)) wide[[start_year]] <- 0
    if (!end_year   %in% names(wide)) wide[[end_year]]   <- 0
    
    wide |>
      dplyr::mutate(
        antall_start = .data[[start_year]],
        antall_siste = .data[[end_year]],
        endring_pct = dplyr::if_else(
          antall_start > 0,
          (antall_siste - antall_start) / antall_start * 100,
          NA_real_
        ),
        label = dplyr::if_else(
          is.na(endring_pct),
          "",
          paste0(
            format(round(endring_pct, 1),
                   decimal.mark = ",",
                   nsmall = 1),
            " %"
          )
        )
      ) |>
      dplyr::arrange(dplyr::desc(endring_pct)) |>
      dplyr::mutate(
        bygnType = factor(as.character(bygnType), levels = as.character(bygnType))
      )
  })
  
  output$bygtype_plot <- renderPlotly({
    req(input$main_tab == "Endringer bygningstyper")
    
    cache_key <- make_key(
      input$nivaa_bygtype,
      input$geografi_bygtype,
      input$periode_bygtype,
      input$hc_mode
    )
    
    if (!is.null(plot_cache$bygtype[[cache_key]])) {
      return(plot_cache$bygtype[[cache_key]])
    }
    
    df <- bygtype_endring_data()
    if (nrow(df) == 0) return(NULL)
    
    max_y <- max(df$endring_pct, na.rm = TRUE)
    y_offset <- max_y * 0.03
    
    p <- ggplot(df, aes(x = bygnType, y = endring_pct)) +
      geom_col(fill = if (isTRUE(input$hc_mode)) "#000000" else "#355047") +
      geom_text(
        aes(
          x = bygnType,
          y = endring_pct + y_offset,
          label = label
        ),
        size = 4.2,
        fontface = "bold",
        color = "black",
        vjust = 0
      ) +
      scale_y_continuous(
        labels = function(x) paste0(x, " %"),
        limits = c(0, max_y * 1.15),
        expand = c(0, 0)
      ) +
      labs(x = NULL, y = NULL) +
      theme_minimal(base_size = 12) +
      theme(
        axis.text.x = element_text(
          angle = 0, hjust = 0.5, vjust = 1, lineheight = 0.9
        ),
        panel.grid.major.x = element_blank(),
        panel.grid.minor = element_blank(),
        plot.margin = margin(5, 20, 10, 30)
      )
    
    p_plotly <- ggplotly(p, tooltip = c("bygnType", "endring_pct")) |>
      layout(
        dragmode = FALSE,
        hovermode = "closest"
      ) |>
      config(displayModeBar = FALSE)
    
    p_plotly <- apply_plotly_cursor_fix(p_plotly)
    plot_cache$bygtype[[cache_key]] <- p_plotly
    p_plotly
  })
  
  ## FANE: FERDIGSTILTE BOLIGER ------------------------------------
  
  observeEvent(input$nivaa_ferdig, {
    if (input$nivaa_ferdig == "Fylke") {
      updatePickerInput(
        session, "geografi_ferdig",
        choices = available_fylker_ferdig,
        selected = "Rogaland"
      )
    } else if (input$nivaa_ferdig == "Kommuner") {
      updatePickerInput(
        session, "geografi_ferdig",
        choices = kommuner_rogaland_ferdig,
        selected = if (length(kommuner_rogaland_ferdig) > 0) kommuner_rogaland_ferdig[1] else NULL
      )
    } else {
      updatePickerInput(
        session, "geografi_ferdig",
        choices = "Norge",
        selected = "Norge"
      )
    }
  }, ignoreInit = TRUE)
  
  output$ferdig_title <- renderText({
    paste0("Ferdigstilte boliger etter bygningstype: ", input$bygn_ferdig)
  })
  
  output$ferdig_region_title <- renderUI({
    label <- if (input$nivaa_ferdig == "Norge") {
      "Norge"
    } else if (is.null(input$geografi_ferdig) || length(input$geografi_ferdig) == 0) {
      paste(input$nivaa_ferdig, "(ingen valg)")
    } else {
      input$geografi_ferdig
    }
    
    tags$p(
      paste("Region  •", label),
      style = "text-align:center; margin-top:-6px; margin-bottom:6px;"
    )
  })
  
  ferdig_data <- reactive({
    req(input$nivaa_ferdig, input$bygn_ferdig)
    
    d <- df_ferdig |>
      dplyr::rename_with(tolower) |>
      dplyr::mutate(
        aar = as.character(aar),
        value = as.numeric(value)
      )
    
    d <- d |>
      dplyr::filter(contents %in% c("Fullforte", "Fullførte", "Fullførte boliger", "Fullførte boliger, antall"))
    
    if (input$bygn_ferdig != "Alle") {
      d <- d |> dplyr::filter(bygtype == input$bygn_ferdig)
    }
    
    if (input$nivaa_ferdig != "Norge" &&
        (is.null(input$geografi_ferdig) || length(input$geografi_ferdig) == 0)) {
      return(d[0, ])
    }
    
    if (input$nivaa_ferdig == "Fylke") {
      d <- d |>
        dplyr::filter(fylke == input$geografi_ferdig) |>
        dplyr::mutate(gruppe = fylke)
      
    } else if (input$nivaa_ferdig == "Kommuner") {
      d <- d |>
        dplyr::filter(
          fylke == "Rogaland",
          region == input$geografi_ferdig
        ) |>
        dplyr::mutate(gruppe = region)
      
    } else {
      d <- d |> dplyr::mutate(gruppe = "Norge")
    }
    
    d |>
      dplyr::group_by(aar, gruppe) |>
      dplyr::summarise(antall = sum(value, na.rm = TRUE), .groups = "drop") |>
      dplyr::mutate(
        aar_i = as.integer(aar)
      ) |>
      dplyr::arrange(dplyr::desc(aar_i)) |>
      dplyr::mutate(
        aar = factor(
          aar,
          levels = sort(unique(aar), decreasing = TRUE)
        ),
        label = format(antall, big.mark = " ", decimal.mark = ",")
      )
  })
  
  output$ferdig_plot <- renderPlotly({
    req(input$main_tab == "Ferdigstilte boliger")
    
    cache_key <- make_key(
      input$nivaa_ferdig,
      input$geografi_ferdig,
      input$bygn_ferdig,
      input$hc_mode
    )
    
    if (!is.null(plot_cache$ferdig[[cache_key]])) {
      return(plot_cache$ferdig[[cache_key]])
    }
    
    df <- ferdig_data()
    if (nrow(df) == 0) return(NULL)
    
    grupper <- levels(factor(df$gruppe))
    
    if (isTRUE(input$hc_mode)) {
      if (input$nivaa_ferdig == "Kommuner") pal <- kommune_palette_hc
      else if (input$nivaa_ferdig == "Fylke") pal <- fylke_palette_hc
      else pal <- norge_palette_hc
    } else {
      if (input$nivaa_ferdig == "Kommuner") pal <- kommune_palette
      else if (input$nivaa_ferdig == "Fylke") pal <- fylke_palette
      else pal <- norge_palette
    }
    
    pal_used <- pal[grupper]
    
    max_x <- max(df$antall, na.rm = TRUE)
    x_pad <- max_x * 0.10
    
    p <- ggplot(df, aes(y = aar, x = antall, fill = gruppe)) +
      geom_col(width = 0.7) +
      geom_text(
        aes(x = antall + x_pad * 0.20, label = label),
        hjust = 0,
        size = 4.2,
        fontface = "bold",
        color = "black"
      ) +
      scale_fill_manual(values = pal_used, name = "Geografisk enhet") +
      scale_x_continuous(
        labels = function(x) format(x, big.mark = " ", decimal.mark = ","),
        limits = c(0, max_x + x_pad),
        expand = c(0, 0)
      ) +
      scale_y_discrete(limits = rev(levels(df$aar))) +
      labs(x = NULL, y = NULL) +
      theme_minimal(base_size = 12) +
      theme(
        panel.grid.major.y = element_blank(),
        panel.grid.minor = element_blank(),
        plot.margin = margin(5, 30, 10, 30)
      )
    
    p_plotly <- ggplotly(p, tooltip = c("aar", "gruppe", "antall")) |>
      layout(
        legend = list(orientation = "h", x = 0, y = 1.15),
        dragmode = FALSE,
        hovermode = "closest"
      ) |>
      config(displayModeBar = FALSE)
    
    p_plotly <- apply_plotly_cursor_fix(p_plotly)
    plot_cache$ferdig[[cache_key]] <- p_plotly
    p_plotly
  })
}

shinyApp(ui, server)
